const crypto = require('crypto');

// Grab the raw webhook body and headers. With rawBody=true on the webhook
// node, n8n gives us the raw bytes under $binary.body (base64-encoded). We
// need the exact bytes GitHub sent for the HMAC to match — re-serializing
// from $json can reorder keys and break verification.
const item = $input.first();
const headers = item.json.headers || {};
let rawBody;
if (item.binary && item.binary.body && item.binary.body.data) {
  rawBody = Buffer.from(item.binary.body.data, 'base64');
} else {
  // Fallback — works only if n8n preserved serialization.
  rawBody = Buffer.from(JSON.stringify(item.json.body || item.json));
}

const sigHeader = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || '';
const secret = $vars.WRILY_WEBHOOK_SECRET;

let signatureValid = false;
try {
  const expected = 'sha256=' + crypto
    .createHmac('sha256', secret)
    .update(rawBody)
    .digest('hex');
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  signatureValid = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  signatureValid = false;
}

// Extract fields we'll need downstream. Parsed body is under $json.body.
const body = item.json.body || item.json;
const pr = body.pull_request || {};
const head = pr.head || {};
const base = pr.base || {};

return [{
  json: {
    signature_valid: signatureValid,
    github_event: headers['x-github-event'] || headers['X-GitHub-Event'] || '',
    action: body.action || '',
    installation_id: body.installation ? body.installation.id : null,
    repository_full_name: body.repository ? body.repository.full_name : '',
    pr_number: pr.number || null,
    head_sha: head.sha || '',
    base_ref: base.ref || '',
  },
}];

const crypto = require('crypto');
const https = require('https');

const item = $input.first().json;
const appId = $vars.WRILY_APP_ID;
const privateKey = $vars.WRILY_APP_PRIVATE_KEY;
const installationId = item.installation_id;
const consumerRepo = item.repository_full_name;

if (!appId || !privateKey) {
  throw new Error('WRILY_APP_ID or WRILY_APP_PRIVATE_KEY not set in n8n Variables');
}
if (!installationId) {
  throw new Error('webhook payload missing installation.id');
}
if (!consumerRepo || !consumerRepo.includes('/')) {
  throw new Error('webhook payload missing repository.full_name');
}

function b64url(input) {
  return Buffer.from(input).toString('base64')
    .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

function createAppJwt() {
  const now = Math.floor(Date.now() / 1000);
  const header = { alg: 'RS256', typ: 'JWT' };
  const payload = { iat: now - 30, exp: now + 540, iss: Number(appId) };
  const data = b64url(JSON.stringify(header)) + '.' + b64url(JSON.stringify(payload));
  const signer = crypto.createSign('RSA-SHA256');
  signer.update(data);
  const signature = signer.sign(privateKey, 'base64')
    .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
  return data + '.' + signature;
}

function mintToken(appJwt, repositories) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ repositories });
    const req = https.request({
      hostname: 'api.github.com',
      path: '/app/installations/' + installationId + '/access_tokens',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + appJwt,
        'Accept': 'application/vnd.github+json',
        'User-Agent': 'wrily-review-dispatcher',
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
      },
    }, (res) => {
      let chunks = '';
      res.on('data', c => chunks += c);
      res.on('end', () => {
        if (res.statusCode !== 201) {
          return reject(new Error('mint token failed (' + res.statusCode + '): ' + chunks));
        }
        try {
          resolve(JSON.parse(chunks).token);
        } catch (e) {
          reject(e);
        }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

const appJwt = createAppJwt();
const consumerRepoName = consumerRepo.split('/')[1];

// Mint in parallel. If the installation covers both wrily and the consumer,
// these are two independent narrow-scope tokens from the same installation.
const [wrilyToken, consumerToken] = await Promise.all([
  mintToken(appJwt, ['wrily']),
  mintToken(appJwt, [consumerRepoName]),
]);

return [{
  json: {
    wrily_token: wrilyToken,
    consumer_token: consumerToken,
    consumer_repo: consumerRepo,
    pr_number: item.pr_number,
    head_sha: item.head_sha,
    base_ref: item.base_ref,
  },
}];
